class Piece:
    def __init__(self, color, position):
        self.color = color
        self.position = position
        self.king = False

    def is_king(self):
        return self.king

    def make_king(self):
        self.king = True


class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = Piece("black", (i, j))
        for i in range(5, 8):
            for j in range(1, 9, 2):
                self.board[i][j] = Piece("red", (i, j))

    def draw(self):
        # Draw the board
        for row in self.board:
            for cell in row:
                if cell is None:
                    print(".", end=" ")
                else:
                    if cell.color == "red":
                        if cell.king:
                            print("R", end=" ")
                        else:
                            print("r", end=" ")
                    else:
                        if cell.king:
                            print("B", end=" ")
                        else:
                            print("b", end=" ")
            print()

    def is_valid_move(self, from_pos, to_pos):
        # Validate the move
        piece = self.board[from_pos[0]][from_pos[1]]
        if piece is None or piece.color != "red":
            return False

        dx, dy = abs(to_pos[0] - from_pos[0]), abs(to_pos[1] - from_pos[1])
        if dx != 1 and dy != 2:
            return False

        intermediate_pos = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
        if self.board[intermediate_pos[0]][intermediate_pos[1]] is None:
            return False

        return True

    def make_move(self, from_pos, to_pos):
        # Make the move
        piece = self.board[from_pos[0]][from_pos[1]]
        intermediate_pos = ((from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2)
        self.board[from_pos[0]][from_pos[1]] = None
        self.board[intermediate_pos[0]][intermediate_pos[1]] = None
        self.board[to_pos[0]][to_pos[1]] = piece

        if to_pos[0] == 7 or to_pos[0] == 0:
            piece.make_king()


class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = "red"

    def run(self):
        while True:
            self.board.draw()
            from_pos = input(f"{self.current_player} enter move (from-to): ")
            to_pos = input("Enter move (to): ")

            try:
                from_pos = tuple(map(int, from_pos.split("-")))
                to_pos = tuple(map(int, to_pos.split("-")))
            except ValueError:
                print("Invalid move format. Please use 'from-to' notation.")
                continue

            if not self.board.is_valid_move(from_pos, to_pos):
                print("Invalid move. Try again.")
                continue

            self.board.make_move(from_pos, to_pos)
            self.current_player = "black" if self.current_player == "red" else "red"


if __name__ == "__main__":
    game = Game()
    game.run()
